args.sparql:
SELECT ?date WHERE {
  ?round wdt:P31 wd:Q3688208 .
  ?round wdt:P361 wd:Q41597 .
  ?round rdfs:label "Quarter-finals"@en .
  ?round wdt:P585 ?date .
}

SELECT ?date WHERE {
  ?round wdt:P31 wd:Q3688208 .
  ?round wdt:P361 wd:Q41597 .
  ?round rdfs:label "Quarterfinals"@en .
  ?round wdt:P585 ?date .
}

SELECT ?date WHERE {
  ?round wdt:P31 wd:Q3688208 .
  ?round wdt:P361 wd:Q41597 .
  ?round wdt:P1453 "Quarter-finals" .
  ?round wdt:P585 ?date .
}

SELECT ?round ?label WHERE {
  wd:Q41597 wdt:P361 ?round .
  ?round rdfs:label ?label .
  FILTER(LANG(?label) = 'en') .
}

SELECT ?date WHERE {
  wd:Q41597 wdt:P361 ?season .
  ?season wdt:P361 / wdt:P361 ?quarterRound .
  ?quarterRound rdfs:label "Quarter-finals"@en .
  ?quarterRound wdt:P585 ?date
}

SELECT ?date WHERE {
  ?season wdt:P361 wd:Q18756;
          rdfs:label ?seasonLabel.
  FILTER (LANG(?seasonLabel) = 'en' && CONTAINS(STR(?seasonLabel), '2023'))
  ?round wdt:P361 ?season;
          rdfs:label 'Quarterfinals'@en.
  ?round wdt:P585 ?date.
  FILTER (datatype(?date) = xsd:dateTime)
} ORDER BY ASC(?date) LIMIT 1

SELECT ?season ?seasonLabel WHERE {
  wd:Q18756 wdt:P1545 ?season.
  ?season rdfs:label ?seasonLabel.
  FILTER (LANG(?seasonLabel) = 'en')
} LIMIT 10
